#include <stdio.h>
#include <stdlib.h>
#define MAXN 200000
int visited[MAXN], order[MAXN];
int pos = 0;
void dfs(int v, int **g, int n) {
    visited[v] = 1;
    for (int i = 0; i < n; i++) {
        if (g[v][i] == 1) {
            if (visited[i] == 1) {
                printf("-1\n");
                exit(0);
            }
            if (visited[i] == 0) {
                dfs(i, g, n);
            }
        }
    }
    visited[v] = 2;
    order[pos++] = v;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int **g = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            g[i] = (int *)malloc(n * sizeof(int));
            for (int j = 0; j < n; j++) {
                g[i][j] = 0;
            }
        }
        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            g[u - 1][v - 1] = 1;
        }
        pos = 0;
        for (int i = 0; i < n; i++) {
            visited[i] = 0;
        }
        for (int i = 0; i < n; i++) {
            if (visited[i] == 0) {
                dfs(i, g, n);
            }
        }
        for (int i = n - 1; i >= 0; i--) {
            printf("%d ", order[i] + 1);
        }
        printf("\n");
        for (int i = 0; i < n; i++) {
            free(g[i]);
        }
        free(g);
    }
    return 0;
}

