code.Java:
import java.io.*;
import java.util.*;
public class Main {
    static final int MAXN = 200000;
    public static void dfs(int v, ArrayList<ArrayList<Integer>> g, int[] visited, ArrayList<Integer> order) {
        visited[v] = 1;
        for (int i = 0; i < g.get(v).size(); i++) {
            if (visited[g.get(v).get(i)] == 1) {
                System.out.println(-1);
                System.exit(0);
            }
            if (visited[g.get(v).get(i)] == 0) {
                dfs(g.get(v).get(i), g, visited, order);
            }
        }
        visited[v] = 2;
        order.add(v);
    }
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int t = Integer.parseInt(br.readLine());
        while (t-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            ArrayList<ArrayList<Integer>> g = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                g.add(new ArrayList<>());
            }
            for (int i = 0; i < m; i++) {
                st = new StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken());
                int v = Integer.parseInt(st.nextToken());
                g.get(u - 1).add(v - 1);
            }
            int[] visited = new int[n];
            ArrayList<Integer> order = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                if (visited[i] == 0) {
                    dfs(i, g, visited, order);
                }
            }
            for (int i = n - 1; i >= 0; i--) {
                System.out.print((order.get(i) + 1) + " ");
            }
            System.out.println();
        }
    }
}

